#include<bits/stdc++.h>
using namespace std;
bool f(int a){
	for(int i=2;i*i<=a;i++)
		if(a%i==0) return 0;
	return 1;
}
int s(int sb){
	int i=0;
	while(pow(10,i)<=sb)i++;
	return i+1;
}
int main()
{
	int c,b,k,o,p,u,g,ot;
	cin>>c>>b;
	if(c<6)cout<<5<<endl;
	if(b>6&&c<=10)cout<<7<<endl;
	for(k=s(c)-1;k<=s(b)-1;k++){
		if(k==2&&b>=11)cout<<11<<endl;
		if(k==3){
			for(o=1;o<10;o+=2){
     			for(p=0;p<10;p++){
        			ot=o*101+p*10;
        			if(f(ot)&&ot<=b&&c<=ot)cout<<ot<<endl;
        		 }
        	}
		}
		if(k==5){
			for(o=1;o<10;o+=2){
     			 for(p=0;p<10;p++){
        			 for(u=0;u<10;u++){
        			 	 ot=10001*o+1010*p+100*u;
       				     if(f(ot)&&ot<=b&&c<=ot)cout<<ot<<endl;
   				     }
   				 }
 			}
		}
		if(k==7){
			for(o=1;o<10;o+=2){
     			for(p=0;p<10;p++){
        			for(u=0;u<10;u++){
        			 	for(g=0;g<10;g++){
        			 		ot=g*1000+u*10100+p*100010+o*1000001;
        			 	 	if(f(ot)&&ot<=b&&c<=ot)cout<<ot<<endl;
						}
   				    }
   				}
 			}
		}
	}
	return 0;
}
